export function reportSa(event: string, jsonObj: any = {}) {
  console.log('reportSa>>', event, jsonObj)
  const v = Object.keys(jsonObj)
    .map((k) => `${k}=${encodeURIComponent(jsonObj[k])}`)
    .join('&')
  window.location.href = `sawaksa://${event}/?${v}`
}

export function reportLoginClick(source: string) {
  reportSa('baloot_login_click', { source })
  return new Promise((r) => setTimeout(r, 300))
}

export function reportLoginFail(source: string, reason: string) {
  reportSa('baloot_login_fail', { source, reason })
}
